using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class ChargeAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    // ── Happy-path ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    // ── Null / empty argument guards ────────────────────────────

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await _gateway.ChargeAsync(null!, 10m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync(string.Empty, 10m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync("   ", 10m);
    }

    // ── Invalid amount guards ───────────────────────────────────

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid_visa", 0m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid_visa", -5m);
    }

    // ── Declined card scenario ──────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        // Convention: tokens starting with "tok_declined" simulate a decline
        var result = await _gateway.ChargeAsync("tok_declined", 50m);

        Assert.IsFalse(result.Success);
    }

    // ── Idempotency ─────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_CalledTwice_ReturnsDifferentChargeIds()
    {
        var first  = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var second = await _gateway.ChargeAsync("tok_valid_visa", 10m);

        Assert.AreNotEqual(first.ChargeId, second.ChargeId);
    }
}

[TestClass]
public class RefundAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    // ── Happy-path ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var result = await _gateway.RefundAsync("ch_abc123");

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.RefundId));
    }

    // ── Null / empty argument guards ────────────────────────────

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync(string.Empty);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_WhitespaceChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync("   ");
    }

    // ── Unknown charge ──────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    // ── Double-refund guard ─────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        // First refund succeeds
        var first = await _gateway.RefundAsync("ch_already_refunded");

        // Second refund on same charge should not succeed
        var second = await _gateway.RefundAsync("ch_already_refunded");

        Assert.IsFalse(second.Success);
    }
}

